evaluators.evaluation_logic:
const checkpoints = [];

const dogs = JSON.parse(localStorage.getItem('dog_profiles') || '[]');
const breeds = JSON.parse(localStorage.getItem('dog_breeds') || '[]');
const dogActivities = JSON.parse(localStorage.getItem('dog_activities') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');
const baseline = metadata && metadata.generatedAt ? new Date(metadata.generatedAt) : null;

// Consider only profiles created after initial dataset load, if baseline is available
const recentDogs = dogs.filter(d => {
  if (!baseline) return true;
  const createdAt = d.createdAt ? new Date(d.createdAt) : null;
  return createdAt && createdAt > baseline;
});

// Recent dogs that are herding-breed, in Agility Stars, and club-members visibility
const herdingAgilityDogs = recentDogs.filter(d => {
  const breed = breeds.find(b => b.id === d.breedId);
  return (
    breed &&
    breed.group === 'Herding' &&
    d.sectionId === 'agility_stars' &&
    d.visibility === 'club_members'
  );
});

// Among those, require 120–150 word bio and exactly three activity tags
const fullyQualifyingDogs = herdingAgilityDogs.filter(d => {
  const wordCount = typeof d.bioWordCount === 'number' ? d.bioWordCount : 0;
  const activities = dogActivities.filter(da => da.dogProfileId === d.id);
  return wordCount >= 120 && wordCount <= 150 && activities.length === 3;
});

// CP1 (0.5): At least one recent herding-group dog in Agility Stars with club-only visibility
checkpoints.push({
  passed: herdingAgilityDogs.length >= 1,
  weight: 0.5
});

// CP2 (0.5): At least one such dog also has a 120–150 word bio and exactly three activities
checkpoints.push({
  passed: fullyQualifyingDogs.length >= 1,
  weight: 0.5
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const ads = JSON.parse(localStorage.getItem('yearbook_ads') || '[]');
const adSizes = JSON.parse(localStorage.getItem('ad_sizes') || '[]');
const adAddonsJoin = JSON.parse(localStorage.getItem('yearbook_ad_addons') || '[]');

// Find the cheapest half-page size costing at most $60
const halfPageSizes = adSizes
  .filter(s => s.category === 'half_page' && s.isActive !== false && (s.price || 0) <= 60)
  .sort((a, b) => (a.price || 0) - (b.price || 0));

const cheapest = halfPageSizes[0] || null;

let sizeAndCostQualified = [];
let fullyQualifiedAds = [];

if (cheapest) {
  const candidates = ads.filter(a => {
    const size = adSizes.find(s => s.id === a.adSizeId);
    if (!size) return false;
    if (a.adSizeId !== cheapest.id) return false;
    if (typeof a.basePrice !== 'number' || a.basePrice !== size.price) return false;
    if (typeof a.addonsTotal !== 'number' || a.addonsTotal !== 0) return false;
    if (typeof a.totalPrice !== 'number' || a.totalPrice > 60) return false;
    // Ensure no add-on join rows exist
    const addonsForAd = adAddonsJoin.filter(j => j.yearbookAdId === a.id);
    if (addonsForAd.length > 0) return false;
    return true;
  });

  sizeAndCostQualified = candidates;

  fullyQualifiedAds = candidates.filter(a => {
    const wc = typeof a.adTextWordCount === 'number' ? a.adTextWordCount : 0;
    return (
      wc >= 100 && wc <= 130 &&
      a.placementOptionId === 'general_dog_tributes' &&
      a.proofingMethod === 'online_only'
    );
  });
}

// CP1 (0.5): At least one ad uses the cheapest qualifying half-page size with no add-ons and total ≤ $60
checkpoints.push({
  passed: !!cheapest && sizeAndCostQualified.length >= 1,
  weight: 0.5
});

// CP2 (0.5): Among those, at least one ad has 100–130 words, General Dog Tributes placement, and online-only proofing
checkpoints.push({
  passed: fullyQualifiedAds.length >= 1,
  weight: 0.5
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const spreads = JSON.parse(localStorage.getItem('spreads') || '[]');
const layouts = JSON.parse(localStorage.getItem('layouts') || '[]');
const sections = JSON.parse(localStorage.getItem('yearbook_sections') || '[]');
const dogs = JSON.parse(localStorage.getItem('dog_profiles') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');
const baseline = metadata && metadata.generatedAt ? new Date(metadata.generatedAt) : null;

// Cheapest two-dog layout supporting at least 200 words
const candidateLayouts = layouts
  .filter(l => (
    l.spreadType === 'two_dog_feature' &&
    l.isActive !== false &&
    l.supportsDogCount >= 2 &&
    typeof l.minTextWords === 'number' && l.minTextWords >= 200
  ))
  .sort((a, b) => (a.price || 0) - (b.price || 0));

const cheapest = candidateLayouts[0] || null;

let newSpreads = [];
let textQualified = [];

if (cheapest) {
  newSpreads = spreads.filter(s => {
    if (s.spreadType !== 'two_dog_feature') return false;
    if (s.layoutId !== cheapest.id) return false;
    // Section must be Companions & Families style
    const section = sections.find(sec => sec.id === s.sectionId);
    if (!section) return false;
    if (section.id !== 'companions_families' && section.code !== 'companions_families') return false;
    // Exactly two existing, distinct dogs
    if (!s.dog1Id || !s.dog2Id || s.dog1Id === s.dog2Id) return false;
    const dog1 = dogs.find(d => d.id === s.dog1Id);
    const dog2 = dogs.find(d => d.id === s.dog2Id);
    if (!dog1 || !dog2) return false;
    // Ensure it was created after initial dataset
    const createdAt = s.createdAt ? new Date(s.createdAt) : null;
    if (baseline && (!createdAt || createdAt <= baseline)) return false;
    return true;
  });

  textQualified = newSpreads.filter(s => {
    const wc = typeof s.textWordCount === 'number' ? s.textWordCount : 0;
    return wc >= 200;
  });
}

// CP1 (0.6): New spread uses cheapest qualifying two-dog layout and is in Companions & Families with two existing dogs
checkpoints.push({
  passed: !!cheapest && newSpreads.length >= 1,
  weight: 0.6
});

// CP2 (0.4): Such a spread has at least 200 words of text
checkpoints.push({
  passed: textQualified.length >= 1,
  weight: 0.4
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const achievements = JSON.parse(localStorage.getItem('achievements') || '[]');
const sortPrefs = JSON.parse(localStorage.getItem('achievements_sort_preferences') || '[]');
const filterParams = JSON.parse(localStorage.getItem('task4_achievementsFilterParams') || 'null');

const targetDogId = 'nova';

// Achievements for Nova dated between 2020 and 2024 inclusive
const inRange = achievements.filter(a => {
  if (a.dogProfileId !== targetDogId) return false;
  if (!a.date) return false;
  const dt = new Date(a.date);
  if (isNaN(dt.getTime())) return false;
  const year = dt.getFullYear();
  return year >= 2020 && year <= 2024;
});

let agilityCount = 0;
let obedienceCount = 0;
inRange.forEach(a => {
  if (a.type === 'agility') agilityCount += 1;
  if (a.type === 'obedience') obedienceCount += 1;
});

const totalInRange = inRange.length;

// CP1 (0.4): Nova has ≥4 in-range achievements with at least 2 agility and 2 obedience
const cp1Passed = totalInRange >= 4 && agilityCount >= 2 && obedienceCount >= 2;
checkpoints.push({ passed: cp1Passed, weight: 0.4 });

// CP2 (0.3): Filter params used for listing match Nova, 2020–2024, minEvents ≥4, sort by date asc
let cp2Passed = false;
if (filterParams) {
  cp2Passed = (
    filterParams.dogProfileId === targetDogId &&
    filterParams.fromYear === 2020 &&
    filterParams.toYear === 2024 &&
    (filterParams.minEvents == null || filterParams.minEvents >= 4) &&
    filterParams.sortBy === 'date' &&
    filterParams.sortDirection === 'asc'
  );
}
checkpoints.push({ passed: cp2Passed, weight: 0.3 });

// CP3 (0.3): Saved sort preference for Nova is date ascending
const pref = sortPrefs.find(p => p.dogProfileId === targetDogId);
const cp3Passed = !!pref && pref.sortBy === 'date' && pref.sortDirection === 'asc';
checkpoints.push({ passed: cp3Passed, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const proofs = JSON.parse(localStorage.getItem('proofs') || '[]');
const comments = JSON.parse(localStorage.getItem('proof_comments') || '[]');

const proof = proofs.find(p => p.id === 'proof_bella_profile_2025');

// CP1 (0.5): Proof decision is approve_with_changes with auto-approval enabled in 3 days
const cp1Passed = !!proof &&
  proof.itemType === 'dog_profile' &&
  proof.approvalDecision === 'approve_with_changes' &&
  proof.autoApprovalEnabled === true &&
  proof.autoApprovalDays === 3;
checkpoints.push({ passed: cp1Passed, weight: 0.5 });

// CP2 (0.5): At least one editors_only comment and one private comment on this proof
let cp2Passed = false;
if (proof) {
  const forProof = comments.filter(c => c.proofId === proof.id);
  const hasEditorOnly = forProof.some(c => c.visibility === 'editors_only');
  const hasPrivate = forProof.some(c => c.visibility === 'private');
  cp2Passed = hasEditorOnly && hasPrivate;
}
checkpoints.push({ passed: cp2Passed, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const orders = JSON.parse(localStorage.getItem('yearbook_orders') || '[]');
const editions = JSON.parse(localStorage.getItem('yearbook_editions') || '[]');
const shippingMethods = JSON.parse(localStorage.getItem('shipping_methods') || '[]');

function calcShipping(method, qty, binding) {
  if (!method) return 0;
  const base = Number(method.baseCost) || 0;
  const q = Number(qty) || 0;
  let perAdditional = Number(method.costPerAdditionalCopy) || 0;
  if (binding === 'softcover') {
    perAdditional = 0;
  }
  if (q <= 0) return 0;
  return base + perAdditional * Math.max(0, q - 1);
}

const edition2025 = editions.find(e => e.year === 2025);

let candidateOrders = [];
let shippingQualifiedOrders = [];

if (edition2025) {
  candidateOrders = orders.filter(o => (
    o.editionId === edition2025.id &&
    o.quantity === 3 &&
    o.binding === 'softcover' &&
    o.paymentMethod === 'pay_later_invoice'
  ));

  if (candidateOrders.length > 0) {
    const qty = 3;
    const binding = 'softcover';

    const underCap = shippingMethods
      .filter(m => m.isActive !== false)
      .map(m => ({ m, cost: calcShipping(m, qty, binding) }))
      .filter(x => x.cost < 10)
      .sort((a, b) => a.cost - b.cost);

    const cheapest = underCap[0] || null;

    if (cheapest) {
      shippingQualifiedOrders = candidateOrders.filter(o => (
        o.shippingMethodId === cheapest.m.id &&
        Math.abs((o.shippingCost || 0) - cheapest.cost) < 0.01 &&
        (o.shippingCost || 0) < 10
      ));
    }
  }
}

// CP1 (0.6): An order exists for 3 softcover copies of the 2025 yearbook with pay-later invoice
checkpoints.push({
  passed: candidateOrders.length >= 1,
  weight: 0.6
});

// CP2 (0.4): Such an order uses the cheapest shipping method under $10 with matching calculated cost
checkpoints.push({
  passed: shippingQualifiedOrders.length >= 1,
  weight: 0.4
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const dogs = JSON.parse(localStorage.getItem('dog_profiles') || '[]');

function calcWordCountForDog(d) {
  if (typeof d.bioWordCount === 'number') return d.bioWordCount;
  if (!d.biography || typeof d.biography !== 'string') return 0;
  const trimmed = d.biography.trim();
  if (!trimmed) return 0;
  const count = trimmed.split(/\s+/).filter(Boolean).length;
  return Math.max(0, count - 1);
}

const longDogs = [];
const shortDogs = [];

dogs.forEach(d => {
  const wc = calcWordCountForDog(d);
  if (wc >= 80) {
    longDogs.push(d);
  } else {
    shortDogs.push(d);
  }
});

const allLongCorrect = longDogs.every(d => d.status === 'final' && d.isLocked === true);
const allShortCorrect = shortDogs.every(d => d.status === 'draft' && !d.isLocked);

// CP1 (0.5): All dogs with bio word count ≥80 are Final and locked
checkpoints.push({
  passed: allLongCorrect,
  weight: 0.5
});

// CP2 (0.5): All dogs with bio word count <80 are Draft and unlocked
checkpoints.push({
  passed: allShortCorrect,
  weight: 0.5
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const sponsorships = JSON.parse(localStorage.getItem('sponsorships') || '[]');
const packages = JSON.parse(localStorage.getItem('sponsorship_packages') || '[]');
const dogs = JSON.parse(localStorage.getItem('dog_profiles') || '[]');

// Find most expensive package with price ≤75
const eligiblePackages = packages
  .filter(p => p.isActive !== false && (p.price || 0) <= 75)
  .sort((a, b) => (a.price || 0) - (b.price || 0));

const targetPkg = eligiblePackages.length ? eligiblePackages[eligiblePackages.length - 1] : null;

let pkgAndDogQualified = [];
let fullyQualified = [];

if (targetPkg) {
  pkgAndDogQualified = sponsorships.filter(s => {
    if (s.sponsorshipPackageId !== targetPkg.id) return false;
    const dog = dogs.find(d => d.id === s.dogProfileId);
    if (!dog) return false;
    if (typeof s.totalPrice !== 'number' || s.totalPrice !== (targetPkg.price || 0)) return false;
    return true;
  });

  fullyQualified = pkgAndDogQualified.filter(s => {
    if (!s.sponsorName || typeof s.sponsorName !== 'string' || !s.sponsorName.trim()) return false;
    const wc = typeof s.sponsorMessageWordCount === 'number' ? s.sponsorMessageWordCount : 0;
    return wc >= 30 && wc <= 40;
  });
}

// CP1 (0.5): Sponsorship exists using the most expensive package ≤$75 and assigned to an existing dog with correct total price
checkpoints.push({
  passed: !!targetPkg && pkgAndDogQualified.length >= 1,
  weight: 0.5
});

// CP2 (0.5): Such a sponsorship has a non-empty sponsor name and a 30–40 word message
checkpoints.push({
  passed: fullyQualified.length >= 1,
  weight: 0.5
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
